// Problem statement - Consider a game where there are n children(numbered 1,
// 2,…, n) in a circle.During the game, every second child is removed from the
// circle, until there are no children left.In which order will the children be
// removed?

// problem link - https://cses.fi/problemset/task/2162/

#include <bits/stdc++.h>
#define ll long long
using namespace std;

void solve() {
    ll n;
    cin >> n;
    set<ll> s;
    for (int i = 1; i <= n; i++) s.insert(i);
    auto it = s.begin();
    ll c = 0;
    ll cnt = n;
    while (cnt != 1) {
        --cnt;
        if (c < 1) {
            ++c;
            ++it;
        }
        if (it == s.end())
            it = s.begin();
        if (c) {
            cout << *it << " ";

            s.erase(it++);
            if (it == s.end())
                it = s.begin();
            c = 0;
            if (it == s.end())
                it = s.begin();
        }
    }
    cout << *s.begin() << endl;
}
//----------------------Main----------------------------//

int main() {
    FIO;

    // test case - 7
    // output - 2 4 6 1 5 3 7

    solve();

    return 0;
}

public class JosephusProblem {
    public static int josephus(int n, int k) {
        if (n <= 0 || k <= 0) {
            return 0;
        }
        int result = 0;
        for (int size = 2; size <= n; size++) {
            result = (result + k) % size;
        }
        return result;
    }
}

fun josephus(n: Int, k: Int): Int {
    var survivor = 0
    for (size in 1..n) {
        survivor = (survivor + k) % size
    }
    return survivor
}

func josephus(_ n: Int, _ k: Int) -> Int {
    if n <= 0 || k <= 0 { return 0 }
    var result = 0
    if n == 1 { return 0 }
    for size in 2...n {
        result = (result + k) % size
    }
    return result
}
